const NavDropdown = ({ label, links }: { label: string, links: { path: string, label: string }[] }) => {
  const [isOpen, setIsOpen] = useState(false);
  const timeoutRef = useRef<number | null>(null);

  const handleMouseEnter = () => {
    if (timeoutRef.current) clearTimeout(timeoutRef.current);
    setIsOpen(true);
  };

  const handleMouseLeave = () => {
    timeoutRef.current = window.setTimeout(() => setIsOpen(false), 150);
  };

  return (
    <div 
      className="relative group"
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
    >
      <button className="flex items-center space-x-1.5 text-[11px] font-black uppercase tracking-widest text-slate-800 hover:text-blue-700 transition-colors py-7">
        <span>{label}</span>
        <svg className={`w-3 h-3 transition-transform duration-300 ${isOpen ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 9l-7 7-7-7" />
        </svg>
      </button>

      {isOpen && (
        <div className="absolute top-[90%] left-0 w-60 bg-white shadow-2xl rounded-xl border border-slate-100 py-2 z-50 animate-in fade-in slide-in-from-top-1 duration-200 overflow-hidden">
          {links.map((link, idx) => (
            <Link 
              key={idx} 
              to={link.path} 
              className="block px-6 py-2.5 text-[10px] font-black uppercase tracking-widest text-slate-600 hover:text-blue-700 hover:bg-slate-50 transition-all border-l-4 border-transparent hover:border-blue-700"
            >
              {link.label}
            </Link>
          ))}
        </div>
      )}
    </div>
  );
};

